// Simulate client data lookup - handles both webhook and evaluation inputs
const input = $json.body || $json;
// Support both webhook format (phone/email) and evaluation format (input_phone/input_email)
const phone = input.input_phone || input.phone || '';
const email = input.input_email || input.email || '';

const mockClients = {
  '{{ $env.SECRET_VALUE }}': {
    first_name: 'John',
    last_name: 'Smith',
    company: 'Acme Corp',
    account_type: 'Premium',
    loyalty_tier: 'Gold',
    last_interaction: 'Called 3 days ago about demo',
    notes: 'Prefers morning calls'
  },
  '{{ $env.SECRET_VALUE }}': {
    first_name: 'Jane',
    last_name: 'Doe',
    company: 'Tech Startup Inc',
    account_type: 'Standard',
    loyalty_tier: 'Silver',
    last_interaction: 'First-time caller',
    notes: ''
  }
};

let client = null;
let lookupKey = null;

if (phone && mockClients[phone]) {
  client = mockClients[phone];
  lookupKey = phone;
} else if (email && mockClients[email]) {
  client = mockClients[email];
  lookupKey = email;
}

const latency = Math.floor(Math.random() * 10) + 2;

if (client) {
  return {
    json: {
      success: true,
      client: client,
      cache_hit: true,
      lookup_key: lookupKey,
      latency_ms: latency,
      source: 'mock_database',
      _eval_input: input // Preserve for evaluation comparison
    }
  };
} else {
  return {
    json: {
      success: true,
      client: null,
      cache_hit: false,
      lookup_key: phone || email || 'none',
      latency_ms: latency,
      message: 'Client not found - new caller',
      _eval_input: input // Preserve for evaluation comparison
    }
  };
}
